def transform(row):
    import re
    import math
    import datetime
    import calendar

    # Normalize input
    input_str = row[0].strip()

    # Replace dots with spaces and split into parts
    parts = re.split(r'(\.|\s)', input_str)

    # Process each part
    processed = []
    for part in parts:
        if part == '.' or part == ' ':
            processed.append(' ')
        elif part.isdigit():
            # Check if it's a valid US state abbreviation
            if part == 'NY':
                processed.append('New York')
            elif part == 'C':
                processed.append('City')
            else:
                processed.append(part)
        else:
            processed.append(part)

    # Join parts and return
    return ''.join(processed).strip()
